firmware_template.source:
#include "tcs34725.h"
#include <Wire.h>
#include <Adafruit_TCS34725.h>
static Adafruit_TCS34725 tcs(TCS34725_INTEGRATIONTIME_600MS,TCS34725_GAIN_1X);
static uint16_t _r=0,_g=0,_b=0,_c=0,_ct=0,_lux=0;
static unsigned long _last=0;
void tcs34725_setup(){Wire.begin();if(!tcs.begin()){Serial.println("[tcs34725] Fail!");return;}Serial.println("[tcs34725] OK");}
void tcs34725_loop(){if(millis()-_last<1000)return;_last=millis();tcs.getRawData(&_r,&_g,&_b,&_c);_ct=tcs.calculateColorTemperature_dn40(_r,_g,_b,_c);_lux=tcs.calculateLux(_r,_g,_b);}
uint16_t tcs34725_get_red(){return _r;}
uint16_t tcs34725_get_green(){return _g;}
uint16_t tcs34725_get_blue(){return _b;}
uint16_t tcs34725_get_clear(){return _c;}
uint16_t tcs34725_get_color_temp(){return _ct;}
uint16_t tcs34725_get_lux(){return _lux;}
